#' Univariable Linear Regression
#'
#' 
#' @param data .
#' @param dep .
#' @param covs .
#' @param factors .
#' @param digitsCoef .
#' @param confInt .
#' @param confLevel .
#' @param addRefRowEstimate .
#' @param addN .
#' @param addNLocation .
#' @param digitsPvalue .
#' @param boldPvalue .
#' @param boldPvalueThreshold .
#' @param globalP .
#' @param addStars .
#' @param starsShowCi .
#' @param starsShowP .
#' @param starsShowSe .
#' @param journal .
#' @param compact .
#' @param language .
#' @param boldLabels .
#' @param boldLevels .
#' @param italicizeLabels .
#' @param italicizeLevels .
#' @param addQ .
#' @param qMethod .
#' @param boldQ .
#' @param boldQThreshold .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$status} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$tbl} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$status$asDF}
#'
#' \code{as.data.frame(results$status)}
#'
#' @export
tblUniRegLinear <- function(
    data,
    dep,
    covs,
    factors,
    digitsCoef = "auto",
    confInt = TRUE,
    confLevel = 95,
    addRefRowEstimate = FALSE,
    addN = TRUE,
    addNLocation = "label",
    digitsPvalue = "auto",
    boldPvalue = FALSE,
    boldPvalueThreshold = 0.05,
    globalP = FALSE,
    addStars = FALSE,
    starsShowCi = FALSE,
    starsShowP = FALSE,
    starsShowSe = TRUE,
    journal = "default",
    compact = FALSE,
    language = "en",
    boldLabels = FALSE,
    boldLevels = FALSE,
    italicizeLabels = FALSE,
    italicizeLevels = FALSE,
    addQ = FALSE,
    qMethod = "BH",
    boldQ = FALSE,
    boldQThreshold = 0.05) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("tblUniRegLinear requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dep)) dep <- jmvcore::resolveQuo(jmvcore::enquo(dep))
    if ( ! missing(covs)) covs <- jmvcore::resolveQuo(jmvcore::enquo(covs))
    if ( ! missing(factors)) factors <- jmvcore::resolveQuo(jmvcore::enquo(factors))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dep), dep, NULL),
            `if`( ! missing(covs), covs, NULL),
            `if`( ! missing(factors), factors, NULL))

    for (v in factors) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- tblUniRegLinearOptions$new(
        dep = dep,
        covs = covs,
        factors = factors,
        digitsCoef = digitsCoef,
        confInt = confInt,
        confLevel = confLevel,
        addRefRowEstimate = addRefRowEstimate,
        addN = addN,
        addNLocation = addNLocation,
        digitsPvalue = digitsPvalue,
        boldPvalue = boldPvalue,
        boldPvalueThreshold = boldPvalueThreshold,
        globalP = globalP,
        addStars = addStars,
        starsShowCi = starsShowCi,
        starsShowP = starsShowP,
        starsShowSe = starsShowSe,
        journal = journal,
        compact = compact,
        language = language,
        boldLabels = boldLabels,
        boldLevels = boldLevels,
        italicizeLabels = italicizeLabels,
        italicizeLevels = italicizeLevels,
        addQ = addQ,
        qMethod = qMethod,
        boldQ = boldQ,
        boldQThreshold = boldQThreshold)

    analysis <- tblUniRegLinearClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

